                    if nums[i] < best_left:
                        best_left = nums[i]

            best_right = INF
            for k in range(j + 1, n):
                if nums[k] < peak:
                    if nums[k] < best_right:
                        best_right = nums[k]

            if best_left != INF and best_right != INF:
                ans = min(ans, best_left + peak + best_right)

        return -1 if ans == INF else ans
